const body = $input.first().json.body || $input.first().json;
const rating = Number(body.rating);
const review = (body.review || '').trim();

if (!review) throw new Error('Review text is required');
if (!Number.isInteger(rating) || rating < 1 || rating > 5) {
  throw new Error('Rating must be an integer between 1 and 5');
}

return [{ json: { rating, review } }];

const { rating, review } = $('Validate Input').first().json;
let raw = $input.first().json.text || $input.first().json.output || '';
raw = String(raw).replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();

const allowed = {
  category: ['bug', 'feature', 'ux', 'billing', 'performance', 'other'],
  severity: ['critical', 'high', 'medium', 'low'],
  sentiment: ['positive', 'negative', 'neutral'],
};

function parseLabels(text) {
  try { return JSON.parse(text); } catch {}
  const match = text.match(/\{[\s\S]*\}/);
  if (match) return JSON.parse(match[0]);
  throw new Error(`Model did not return JSON. Got: ${text.slice(0, 120)}`);
}

const labels = parseLabels(raw);

for (const [field, values] of Object.entries(allowed)) {
  if (!values.includes(labels[field])) labels[field] = field === 'category' ? 'other' : field === 'severity' ? 'medium' : 'neutral';
}

return [{
  json: {
    rating,
    raw_text: review,
    summary: String(labels.summary || review).slice(0, 200),
    category: labels.category,
    severity: labels.severity,
    sentiment: labels.sentiment,
    product_area: labels.product_area || null,
  }
}];

